#include <stdio.h>
#include <stdlib.h>

// Node structure for the binary tree
struct Node {
    int data;
    struct Node* left;
    struct Node* right;
};

// Function to create a new node
struct Node* newNode(int val) {
    struct Node* node = (struct Node*)malloc(sizeof(struct Node));
    node->data = val;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// Function to check if two subtrees are symmetric
int isSymmetricUtil(struct Node* root1, struct Node* root2) {
    if (root1 == NULL || root2 == NULL) {
        return root1 == root2;
    }
    return (root1->data == root2->data) && isSymmetricUtil(root1->left, root2->right) && isSymmetricUtil(root1->right, root2->left);
}

// Public function to check if the entire binary tree is symmetric
int isSymmetric(struct Node* root) {
    if (root == NULL) {
        return 1;
    }
    return isSymmetricUtil(root->left, root->right);
}

int main() {
    // Creating a sample binary tree
    struct Node* root = newNode(1);
    root->left = newNode(2);
    root->right = newNode(2);
    root->left->left = newNode(3);
    root->right->right = newNode(3);
    root->left->right = newNode(4);
    root->right->left = newNode(4);

    if (isSymmetric(root)) {
        printf("This Tree is Symmetrical\n");
    } else {
        printf("This Tree is NOT Symmetrical\n");
    }

    return 0;
}

